/**
 * คำนวณระยะห่างระหว่างจุดพิกัด GPS สองจุด ด้วยสูตร Haversine
 * @param {number} lat1 - ละติจูดของจุดที่ 1 (ตำแหน่งปัจจุบัน)
 * @param {number} lon1 - ลองจิจูดของจุดที่ 1 (ตำแหน่งปัจจุบัน)
 * @param {number} lat2 - ละติจูดของจุดที่ 2 (ตำแหน่งโปรเจค)
 * @param {number} lon2 - ลองจิจูดของจุดที่ 2 (ตำแหน่งโปรเจค)
 * @returns {number} ระยะห่างในเมตร
 */
const calculateDistance = (lat1, lon1, lat2, lon2) => {
  // ถ้ามีค่าใดค่าหนึ่งเป็น null หรือ undefined ให้คืนค่าระยะทางเป็น Infinity
  if (!lat1 || !lon1 || !lat2 || !lon2) {
    return Infinity;
  }

  // แปลงค่าละติจูด ลองจิจูดจากองศาเป็นเรเดียน
  const toRadian = (degree) => (degree * Math?.PI) / 180;

  const R = 6371000; // รัศมีของโลกในหน่วยเมตร
  const φ1 = toRadian(lat1);
  const φ2 = toRadian(lat2);
  const Δφ = toRadian(lat2 - lat1);
  const Δλ = toRadian(lon2 - lon1);

  // สูตร Haversine
  const a =
    Math?.sin(Δφ / 2) * Math?.sin(Δφ / 2) +
    Math?.cos(φ1) * Math?.cos(φ2) * Math?.sin(Δλ / 2) * Math?.sin(Δλ / 2);
  const c = 2 * Math?.atan2(Math?.sqrt(a), Math?.sqrt(1 - a));
  const distance = R * c;

  return distance;
};

/**
 * คำนวณระยะห่างจากตำแหน่งปัจจุบันไปยังโปรเจคและหาโปรเจคที่ใกล้ที่สุด
 * @param {Object} coords - ตำแหน่งปัจจุบัน (latitude, longitude)
 * @param {Array|Object} projects - โปรเจคเดี่ยวหรือรายการโปรเจค
 * @param {number} maxDistance - ระยะห่างสูงสุดในเมตรที่ยอมรับได้ (ค่าเริ่มต้น: 100 เมตร)
 * @returns {Object} ข้อมูลตำแหน่งและโปรเจคที่ใกล้ที่สุด
 */
const CalculateGps = (coords, projects, maxDistance = 100) => {
  // ตรวจสอบว่า projects เป็น array หรือ object เดี่ยว
  const projectArray = Array?.isArray(projects) ? projects : [projects];

  // ข้อมูลพิกัดปัจจุบัน
  const currentLat = coords?.latitude;
  const currentLon = coords?.longitude;

  // คำนวณระยะห่างระหว่างตำแหน่งปัจจุบันกับแต่ละโปรเจค
  const projectsWithDistance = projectArray?.map((project) => {
    // ตรวจสอบว่ามีข้อมูล GPS ของโปรเจคหรือไม่
    if (project?.gps && project?.gps?.lat && project?.gps?.lon) {
      const distance = calculateDistance(
        currentLat,
        currentLon,
        project?.gps?.lat,
        project?.gps?.lon,
      );

      return {
        project: project,
        distance: distance,
        isNearby: distance <= maxDistance,
      };
    }

    // ถ้าโปรเจคไม่มีข้อมูล GPS จะกำหนดระยะทางเป็น Infinity
    return {
      project: project,
      distance: Infinity,
      isNearby: false,
    };
  });

  // เรียงลำดับโปรเจคตามระยะห่าง (ใกล้ไปไกล)
  projectsWithDistance?.sort((a, b) => a?.distance - b?.distance);

  // โปรเจคที่ใกล้ที่สุด
  const nearestProject = projectsWithDistance[0];

  return {
    currentLocation: {
      lat: currentLat,
      lon: currentLon,
    },
    nearestProject: {
      project: nearestProject?.project,
      distance: nearestProject?.distance,
      isNearby: nearestProject?.isNearby,
      distanceText:
        nearestProject?.distance < 1000
          ? `${Math?.round(nearestProject?.distance)} เมตร`
          : `${(nearestProject?.distance / 1000)?.toFixed(2)} กิโลเมตร`,
    },
  };
};

export default CalculateGps;
